     1→import forge from "node-forge";
     2→import axios from "axios";
     3→import { db, afipConfigsTable } from "@workspace/db";
     4→import { eq } from "drizzle-orm";
     5→
     6→const WSAA_HOMO = "https://wsaahomo.afip.gov.ar/ws/services/LoginCms";
     7→const WSAA_PROD = "https://wsaa.afip.gov.ar/ws/services/LoginCms";
     8→
     9→function buildLoginTicketRequest(): string {
    10→  const now    = new Date();
    11→  const expiry = new Date(now.getTime() + 12 * 60 * 60 * 1000);
    12→  const fmt    = (d: Date) => d.toISOString().replace(/\.\d{3}Z$/, "-03:00");
    13→  const uid    = Math.floor(Math.random() * 2_000_000_000);
    14→  return `<?xml version="1.0" encoding="UTF-8"?>
    15→<loginTicketRequest version="1.0">
    16→  <header>
    17→    <uniqueId>${uid}</uniqueId>
    18→    <generationTime>${fmt(now)}</generationTime>
    19→    <expirationTime>${fmt(expiry)}</expirationTime>
    20→  </header>
    21→  <service>wsfe</service>
    22→</loginTicketRequest>`;
    23→}
    24→
    25→function signCms(xmlContent: string, certPem: string, keyPem: string): string {
    26→  const cert       = forge.pki.certificateFromPem(certPem);
    27→  const privateKey = forge.pki.privateKeyFromPem(keyPem);
    28→
    29→  const p7 = forge.pkcs7.createSignedData();
    30→  p7.content = forge.util.createBuffer(xmlContent, "utf8");
    31→  p7.addCertificate(cert);
    32→  p7.addSigner({
    33→    key:                     privateKey,
    34→    certificate:             cert,
    35→    digestAlgorithm:         forge.pki.oids.sha256,
    36→    authenticatedAttributes: [],
    37→  });
    38→  p7.sign({ detached: false });
    39→
    40→  const der = forge.asn1.toDer(p7.toAsn1());
    41→  return forge.util.encode64(der.bytes());
    42→}
    43→
    44→async function callWsaa(cmsCms64: string, url: string): Promise<{ token: string; sign: string; expiry: Date }> {
    45→  const body = `<?xml version="1.0" encoding="UTF-8"?>
    46→<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:wsaa="http://wsaa.view.sua.dvadac.desein.afip.gov.ar">
    47→  <soapenv:Header/>
    48→  <soapenv:Body>
    49→    <wsaa:loginCms>
    50→      <wsaa:in0>${cmsCms64}</wsaa:in0>
    51→    </wsaa:loginCms>
    52→  </soapenv:Body>
    53→</soapenv:Envelope>`;
    54→
    55→  const resp = await axios.post(url, body, {
    56→    headers: {
    57→      "Content-Type": "text/xml;charset=UTF-8",
    58→      "SOAPAction":   "",
    59→    },
    60→    timeout: 30_000,
    61→  });
    62→
    63→  const xml = resp.data as string;
    64→  const token   = xml.match(/<token>([\s\S]*?)<\/token>/)?.[1]?.trim();
    65→  const sign    = xml.match(/<sign>([\s\S]*?)<\/sign>/)?.[1]?.trim();
    66→  const expStrRaw = xml.match(/<expirationTime>([\s\S]*?)<\/expirationTime>/)?.[1]?.trim();
    67→
    68→  if (!token || !sign) throw new Error("WSAA: respuesta inválida — no se encontró token/sign");
    69→
    70→  let expiry = new Date(Date.now() + 12 * 60 * 60 * 1000);
    71→  if (expStrRaw) {
    72→    const parsed = new Date(expStrRaw.replace(/-03:00$/, "Z").replace(/-03:00/, ""));
    73→    if (!isNaN(parsed.getTime())) expiry = parsed;
    74→  }
    75→
    76→  return { token, sign, expiry };
    77→}
    78→
    79→export async function getToken(userId: string): Promise<{ token: string; sign: string; cuit: string; puntoVenta: number }> {
    80→  const [config] = await db.select().from(afipConfigsTable).where(eq(afipConfigsTable.userId, userId)).limit(1);
    81→  if (!config) throw new Error("AFIP no configurado para este usuario");
    82→  if (!config.certPem || !config.privateKeyPem) throw new Error("Certificado AFIP no cargado");
    83→  if (!config.cuit) throw new Error("CUIT no configurado");
    84→  if (!config.puntoVenta) throw new Error("Punto de venta no configurado");
    85→
    86→  const now = new Date();
    87→  if (config.token && config.sign && config.tokenExpiry && config.tokenExpiry > new Date(now.getTime() + 5 * 60 * 1000)) {
    88→    return { token: config.token, sign: config.sign, cuit: config.cuit, puntoVenta: config.puntoVenta };
    89→  }
    90→
    91→  const wsaaUrl = config.environment === "produccion" ? WSAA_PROD : WSAA_HOMO;
    92→  const xml     = buildLoginTicketRequest();
    93→  const cms     = signCms(xml, config.certPem, config.privateKeyPem);
    94→  const { token, sign, expiry } = await callWsaa(cms, wsaaUrl);
    95→
    96→  await db.update(afipConfigsTable)
    97→    .set({ token, sign, tokenExpiry: expiry, updatedAt: new Date() })
    98→    .where(eq(afipConfigsTable.userId, userId));
    99→
   100→  return { token, sign, cuit: config.cuit, puntoVenta: config.puntoVenta };
   101→}
   102→
   103→export async function refreshToken(userId: string): Promise<void> {
   104→  const [config] = await db.select().from(afipConfigsTable).where(eq(afipConfigsTable.userId, userId)).limit(1);
   105→  if (!config?.certPem || !config?.privateKeyPem) throw new Error("Certificado AFIP no configurado");
   106→
   107→  const wsaaUrl = config.environment === "produccion" ? WSAA_PROD : WSAA_HOMO;
   108→  const xml     = buildLoginTicketRequest();
   109→  const cms     = signCms(xml, config.certPem, config.privateKeyPem);
   110→  const { token, sign, expiry } = await callWsaa(cms, wsaaUrl);
   111→
   112→  await db.update(afipConfigsTable)
   113→    .set({ token, sign, tokenExpiry: expiry, updatedAt: new Date() })
   114→    .where(eq(afipConfigsTable.userId, userId));
   115→}
