    27→
    28→function soapHeader(token: string, sign: string, cuit: string): string {
    29→  return `<ar:FEAuthRequest>
    30→    <ar:Token>${token}</ar:Token>
    31→    <ar:Sign>${sign}</ar:Sign>
    32→    <ar:Cuit>${cuit}</ar:Cuit>
    33→  </ar:FEAuthRequest>`;
    34→}
    35→
    36→async function soapCall(url: string, action: string, bodyInner: string): Promise<string> {
    37→  const envelope = `<?xml version="1.0" encoding="UTF-8"?>
    38→<soapenv:Envelope
    39→  xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/"
    40→  xmlns:ar="http://ar.gov.afip.dif.FEV1/">
    41→  <soapenv:Header/>
    42→  <soapenv:Body>${bodyInner}</soapenv:Body>
    43→</soapenv:Envelope>`;
    44→
    45→  const resp = await axios.post(url, envelope, {
    46→    headers: {
    47→      "Content-Type": "text/xml;charset=UTF-8",
    48→      "SOAPAction":   `http://ar.gov.afip.dif.FEV1/${action}`,
    49→    },
    50→    timeout: 30_000,
    51→  });
    52→  return resp.data as string;
    53→}
    54→
    55→function getWsfeUrl(env: string): string {
    56→  return env === "produccion" ? WSFE_PROD : WSFE_HOMO;
    57→}
    58→
    59→export async function ultimoComprobante(
    60→  token: string, sign: string, cuit: string,
    61→  puntoVenta: number, tipo: number, env: string,
    62→): Promise<number> {
    63→  const url  = getWsfeUrl(env);
    64→  const body = `<ar:FECompUltimoAutorizado>
    65→    ${soapHeader(token, sign, cuit)}
    66→    <ar:PtoVta>${puntoVenta}</ar:PtoVta>
    67→    <ar:CbteTipo>${tipo}</ar:CbteTipo>
    68→  </ar:FECompUltimoAutorizado>`;
    69→
    70→  const xml = await soapCall(url, "FECompUltimoAutorizado", body);
    71→  const nro = xml.match(/<CbteNro>(\d+)<\/CbteNro>/)?.[1];
    72→  return nro ? parseInt(nro, 10) : 0;
    73→}
    74→
    75→export async function solicitarCae(
    76→  token: string, sign: string, cuit: string,
    77→  puntoVenta: number, inv: InvoiceData, env: string,
    78→): Promise<CaeResult> {
    79→  const url    = getWsfeUrl(env);
    80→  const ultimo = await ultimoComprobante(token, sign, cuit, puntoVenta, inv.tipo, env);
    81→  const numero = ultimo + 1;
    82→
    83→  const hoy  = new Date().toISOString().slice(0, 10).replace(/-/g, "");
    84→
    85→  const ivaItems = buildIvaItems(inv);
    86→
    87→  const body = `<ar:FECAESolicitar>
    88→    ${soapHeader(token, sign, cuit)}
    89→    <ar:FeCAEReq>
    90→      <ar:FeCabReq>
    91→        <ar:CantReg>1</ar:CantReg>
    92→        <ar:PtoVta>${puntoVenta}</ar:PtoVta>
    93→        <ar:CbteTipo>${inv.tipo}</ar:CbteTipo>
    94→      </ar:FeCabReq>
    95→      <ar:FeDetReq>
    96→        <ar:FECAEDetRequest>
    97→          <ar:Concepto>${inv.concepto}</ar:Concepto>
    98→          <ar:DocTipo>${inv.docTipo}</ar:DocTipo>
    99→          <ar:DocNro>${inv.docNro}</ar:DocNro>
   100→          <ar:CbteDesde>${numero}</ar:CbteDesde>
   101→          <ar:CbteHasta>${numero}</ar:CbteHasta>
   102→          <ar:CbteFch>${hoy}</ar:CbteFch>
   103→          <ar:ImpTotal>${inv.impTotal.toFixed(2)}</ar:ImpTotal>
   104→          <ar:ImpTotConc>0.00</ar:ImpTotConc>
   105→          <ar:ImpNeto>${inv.impNeto.toFixed(2)}</ar:ImpNeto>
   106→          <ar:ImpOpEx>0.00</ar:ImpOpEx>
   107→          <ar:ImpIVA>${inv.impIva.toFixed(2)}</ar:ImpIVA>
   108→          <ar:ImpTrib>0.00</ar:ImpTrib>
   109→          <ar:MonId>PES</ar:MonId>
   110→          <ar:MonCotiz>1</ar:MonCotiz>
   111→          ${ivaItems}
   112→        </ar:FECAEDetRequest>
   113→      </ar:FeDetReq>
   114→    </ar:FeCAEReq>
   115→  </ar:FECAESolicitar>`;
   116→
   117→  const xml = await soapCall(url, "FECAESolicitar", body);
   118→
   119→  const resultado  = xml.match(/<Resultado>(.*?)<\/Resultado>/)?.[1] ?? "E";
   120→  const cae        = xml.match(/<CAE>(.*?)<\/CAE>/)?.[1] ?? "";
   121→  const caeFchVto  = xml.match(/<CAEFchVto>(.*?)<\/CAEFchVto>/)?.[1] ?? "";
   122→  const errores: string[] = [];
   123→
   124→  const errMatches = xml.matchAll(/<Msg>(.*?)<\/Msg>/g);
   125→  for (const m of errMatches) errores.push(m[1]);
   126→
   127→  if (resultado !== "A") {
   128→    throw new Error(`AFIP rechazó la solicitud: ${errores.join(" | ") || "error desconocido"}`);
   129→  }
   130→
   131→  return { numero, cae, caeFchVto, fecha: hoy, resultado, errores };
   132→}
