   134→function buildIvaItems(inv: InvoiceData): string {
   135→  const items: string[] = [];
   136→
   137→  if (inv.iva21Neto && inv.iva21Neto > 0) {
   138→    items.push(`<ar:AlicIva>
   139→      <ar:Id>5</ar:Id>
   140→      <ar:BaseImp>${inv.iva21Neto.toFixed(2)}</ar:BaseImp>
   141→      <ar:Importe>${(inv.iva21Neto * 0.21).toFixed(2)}</ar:Importe>
   142→    </ar:AlicIva>`);
   143→  }
   144→  if (inv.iva105Neto && inv.iva105Neto > 0) {
   145→    items.push(`<ar:AlicIva>
   146→      <ar:Id>4</ar:Id>
   147→      <ar:BaseImp>${inv.iva105Neto.toFixed(2)}</ar:BaseImp>
   148→      <ar:Importe>${(inv.iva105Neto * 0.105).toFixed(2)}</ar:Importe>
   149→    </ar:AlicIva>`);
   150→  }
   151→
   152→  if (items.length === 0 && inv.impIva > 0) {
   153→    items.push(`<ar:AlicIva>
   154→      <ar:Id>5</ar:Id>
   155→      <ar:BaseImp>${inv.impNeto.toFixed(2)}</ar:BaseImp>
   156→      <ar:Importe>${inv.impIva.toFixed(2)}</ar:Importe>
   157→    </ar:AlicIva>`);
   158→  }
   159→
   160→  if (items.length === 0) return "";
   161→  return `<ar:Iva>${items.join("\n")}</ar:Iva>`;
   162→}
